You are a senior code reviewer. Review the following migration from sql.js to better-sqlite3 in an OpenMnemo TypeScript monorepo. Focus on correctness, edge cases, and best practices.

## Files changed:

### 1. packages/core/src/transcript/db.ts (new implementation)
```typescript
import Database from 'better-sqlite3'
import { existsSync, mkdirSync } from 'node:fs'
import { dirname } from 'node:path'
import type { ManifestEntry } from '@openmnemo/types'

const PK_COLUMNS = ['client', 'project', 'session_id', 'raw_sha256'] as const
const DATA_COLUMNS = [
  'title', 'started_at', 'imported_at', 'cwd', 'branch',
  'raw_source_path', 'raw_upload_permission', 'global_raw_path',
  'global_clean_path', 'repo_raw_path', 'repo_clean_path',
  'repo_manifest_path', 'message_count', 'tool_event_count',
] as const
const ALL_COLUMNS = [...PK_COLUMNS, ...DATA_COLUMNS] as const

const CREATE_TABLE_SQL = `
  CREATE TABLE IF NOT EXISTS transcripts (
    client TEXT NOT NULL, project TEXT NOT NULL,
    session_id TEXT NOT NULL, raw_sha256 TEXT NOT NULL,
    title TEXT NOT NULL, started_at TEXT NOT NULL,
    imported_at TEXT NOT NULL, cwd TEXT NOT NULL,
    branch TEXT NOT NULL, raw_source_path TEXT NOT NULL,
    raw_upload_permission TEXT NOT NULL, global_raw_path TEXT NOT NULL,
    global_clean_path TEXT NOT NULL, repo_raw_path TEXT NOT NULL,
    repo_clean_path TEXT NOT NULL, repo_manifest_path TEXT NOT NULL,
    message_count INTEGER NOT NULL, tool_event_count INTEGER NOT NULL,
    PRIMARY KEY (client, project, session_id, raw_sha256)
  )
`

const UPSERT_SQL = `
  INSERT INTO transcripts (${ALL_COLUMNS.join(', ')})
  VALUES (${ALL_COLUMNS.map(() => '?').join(', ')})
  ON CONFLICT(${PK_COLUMNS.join(', ')}) DO UPDATE SET
    ${DATA_COLUMNS.map((c) => `${c} = excluded.${c}`).join(',\n    ')}
`

const CREATE_FTS_SQL = `
  CREATE VIRTUAL TABLE IF NOT EXISTS transcripts_fts USING fts4(
    content='transcripts', title, cwd, branch
  )
`
const REBUILD_FTS_SQL = `INSERT INTO transcripts_fts(transcripts_fts) VALUES('rebuild')`
const SEARCH_SQL = `
  SELECT t.client, t.project, t.session_id, t.title, t.cwd, t.branch, t.started_at
  FROM transcripts_fts
  JOIN transcripts t ON transcripts_fts.docid = t.rowid
  WHERE transcripts_fts MATCH ?
  ORDER BY t.started_at DESC
  LIMIT ?
`

export interface SearchResult {
  client: string; project: string; session_id: string
  title: string; cwd: string; branch: string; started_at: string
}

export function sanitizeFtsQuery(raw: string): string {
  return raw.replace(/[^\p{L}\p{N}\s']/gu, ' ').trim().replace(/\s+/g, ' ')
}

function openDb(dbPath: string): InstanceType<typeof Database> {
  const dir = dirname(dbPath)
  if (!existsSync(dir)) mkdirSync(dir, { recursive: true })
  const db = new Database(dbPath)
  db.pragma('journal_mode = WAL')
  return db
}

export function searchTranscripts(dbPath: string, query: string, limit = 20): SearchResult[] {
  const sanitized = sanitizeFtsQuery(query)
  if (!sanitized) return []
  if (!existsSync(dbPath)) return []

  const db = new Database(dbPath, { readonly: true })
  try {
    db.exec(CREATE_FTS_SQL)
    const segCount = (db.prepare('SELECT COUNT(*) as cnt FROM transcripts_fts_segdir').get() as { cnt: number }).cnt
    if (segCount === 0) db.exec(REBUILD_FTS_SQL)
    const stmt = db.prepare(SEARCH_SQL)
    return stmt.all(sanitized, limit) as SearchResult[]
  } finally {
    db.close()
  }
}

export function upsertSearchIndex(dbPath: string, manifest: ManifestEntry): void {
  const db = openDb(dbPath)
  try {
    db.exec(CREATE_TABLE_SQL)
    const record: Record<string, unknown> = { ...manifest }
    const params = ALL_COLUMNS.map((col) => {
      const value = record[col]
      if (value === undefined || value === null) return ''
      return typeof value === 'number' ? value : String(value)
    })
    db.prepare(UPSERT_SQL).run(...params)
    db.exec(CREATE_FTS_SQL)
    db.exec(REBUILD_FTS_SQL)
  } finally {
    db.close()
  }
}
```

### 2. packages/core/src/recall/recall.ts (key changed section)
```typescript
import Database from 'better-sqlite3'
// ...
export function findLatestSession(
  globalRoot: string, root: string, repoSlug: string, activationTime: string,
): Record<string, unknown> | null {
  const dbPath = join(globalRoot, 'index', 'search.sqlite')
  if (!existsSync(dbPath)) return findLatestFromJsonl(globalRoot, root, repoSlug, activationTime)

  try {
    const db = new Database(dbPath, { readonly: true })
    try {
      const rows = db
        .prepare('SELECT * FROM transcripts WHERE started_at < ? ORDER BY started_at DESC LIMIT 20')
        .all(activationTime) as Record<string, unknown>[]
      const resolvedRoot = toPosixPath(resolve(root)).toLowerCase()
      for (const row of rows) {
        const cwd = String(row['cwd'] ?? '')
        const project = String(row['project'] ?? '')
        if (cwdMatches(cwd, resolvedRoot) || project === repoSlug) return row
      }
    } finally {
      db.close()
    }
  } catch {
    return findLatestFromJsonl(globalRoot, root, repoSlug, activationTime)
  }
  return null
}
```

### 3. packages/core/src/transcript/import.ts (line 105 change)
```typescript
// Before: await upsertSearchIndex(globalDbPath, manifest)
upsertSearchIndex(globalDbPath, manifest)  // now sync
```

## Review criteria:
1. CORRECTNESS: Are there any bugs, logic errors, or incorrect API usage?
2. EDGE CASES: Missing error handling, race conditions, concurrent access issues?
3. BEST PRACTICES: better-sqlite3 specific patterns, WAL mode usage, prepared statement reuse?
4. SECURITY: SQL injection risks, path traversal?
5. PERFORMANCE: Any obvious inefficiencies?

Rate each issue as CRITICAL / HIGH / MEDIUM / LOW. List only real issues, not style preferences.

